  1	import * as React from 'react';
  2	import {
  3	  Button,
  4	  EmptyState,
  5	  EmptyStateIcon,
  6	  EmptyStateBody,
  7	  ButtonVariant,
  8	  EmptyStateVariant
  9	} from '@patternfly/react-core';
 10	import { ChartArea, ChartBar, ChartScatter, ChartLine } from '@patternfly/react-charts';
 11	import { CubesIcon, ErrorCircleOIcon } from '@patternfly/react-icons';
 12	
 13	import { ChartModel } from 'types/Dashboards';
 14	import { VCLines, RawOrBucket, RichDataPoint, LineInfo } from 'types/VictoryChartInfo';
 15	import { Overlay } from 'types/Overlay';
 16	import { ChartWithLegend, LEGEND_HEIGHT, MIN_HEIGHT, MIN_HEIGHT_YAXIS } from './ChartWithLegend';
 17	import { BrushHandlers } from './Container';
 18	import { KialiIcon } from '../../config/KialiIcon';
 19	import { kialiStyle } from 'styles/StyleUtils';
 20	import { PFColors } from 'components/Pf/PfColors';
 21	
 22	type KChartProps<T extends LineInfo> = {
 23	  chart: ChartModel;
 24	  chartHeight?: number;
 25	  data: VCLines<RichDataPoint>;
 26	  isMaximized: boolean;
 27	  onToggleMaximized: () => void;
 28	  onClick?: (datum: RawOrBucket<T>) => void;
 29	  showSpans: boolean;
 30	  showTrendline?: boolean;
 31	  brushHandlers?: BrushHandlers;
 32	  overlay?: Overlay<T>;
 33	  timeWindow?: [Date, Date];
 34	};
 35	
 36	export const maximizeButtonStyle: React.CSSProperties = {
 37	  position: 'relative',
 38	  float: 'right'
 39	};
 40	
 41	const emptyStyle = kialiStyle({
 42	  padding: '0 0 0 0',
 43	  margin: '0 0 0 0'
 44	});
 45	
 46	const kchartStyle = kialiStyle({
 47	  paddingTop: 15,
 48	  paddingLeft: 25,
 49	  paddingRight: 25,
 50	  paddingBottom: 12
 51	});
 52	
 53	// 24px (title + toolbar) + 20px (margin) + 15px (padding) + 15px (padding)
 54	const titlePadding = 64;
 55	
 56	type State = {
 57	  collapsed: boolean;
 58	};
 59	
 60	type ChartTypeData = {
 61	  fill: boolean;
 62	  stroke: boolean;
 63	  groupOffset: number;
 64	  seriesComponent: React.ReactElement;
 65	  sizeRatio: number;
 66	};
 67	
 68	const lineInfo: ChartTypeData = {
 69	  fill: false,
 70	  stroke: true,
 71	  groupOffset: 0,
 72	  seriesComponent: <ChartLine />,
 73	  sizeRatio: 1.0
 74	};
 75	const areaInfo: ChartTypeData = {
 76	  fill: true,
 77	  stroke: false,
 78	  groupOffset: 0,
 79	  seriesComponent: <ChartArea />,
 80	  sizeRatio: 1.0
 81	};
 82	const barInfo: ChartTypeData = {
 83	  fill: true,
 84	  stroke: false,
 85	  groupOffset: 7,
 86	  seriesComponent: <ChartBar />,
 87	  sizeRatio: 1 / 6
 88	};
 89	const scatterInfo: ChartTypeData = {
 90	  fill: true,
 91	  stroke: false,
 92	  groupOffset: 0,
 93	  seriesComponent: <ChartScatter />,
 94	  sizeRatio: 1 / 30
 95	};
 96	
 97	export class KChart<T extends LineInfo> extends React.Component<KChartProps<T>, State> {
 98	  constructor(props: KChartProps<T>) {
 99	    super(props);
100	    this.state = {
101	      collapsed: this.props.chart.startCollapsed || (!this.props.chart.error && this.isEmpty())
102	    };
103	  }
104	
105	  componentDidUpdate(prevProps: KChartProps<T>) {
106	    // Check when there is a change on empty datapoints on a refresh to draw the chart collapsed the first time
107	    // User can change the state after that point
108	    const propsIsEmpty = !this.props.data.some(s => s.datapoints.length !== 0);
109	    const prevPropsIsEmpty = !prevProps.data.some(s => s.datapoints.length !== 0);
110	    if (propsIsEmpty !== prevPropsIsEmpty) {
111	      this.setState({
112	        collapsed: propsIsEmpty
113	      });
114	    }
115	  }
116	
117	  private getInnerChartHeight = (): number => {
118	    const chartHeight: number = this.props.chartHeight || 300;
119	    const innerChartHeight = chartHeight - titlePadding;
120	    return innerChartHeight;
121	  };
122	
123	  render() {
124	    return (
125	      <div className={kchartStyle}>
126	        <div
127	          style={{
128	            display: 'flex',
129	            justifyContent: 'space-between'
130	          }}
131	        >
132	          <div
133	            style={{
134	              minWidth: '0px',
135	              display: 'inline-block',
136	              whiteSpace: 'nowrap',
137	              overflow: 'hidden',
138	              textOverflow: 'ellipsis'
139	            }}
140	          >
141	            {this.props.chart.name}
142	          </div>
143	          {this.props.onToggleMaximized && (
144	            <div style={maximizeButtonStyle}>
145	              <Button variant={ButtonVariant.link} onClick={this.props.onToggleMaximized} isInline>
146	                <KialiIcon.Expand />
147	              </Button>
148	            </div>
149	          )}
150	        </div>
151	        <div style={{ marginTop: 20 }} data-test={'metrics-chart'}>
152	          {this.props.chart.error ? this.renderError() : this.isEmpty() ? this.renderEmpty() : this.renderChart()}
153	        </div>
154	      </div>
155	    );
156	  }
157	
158	  private determineChartType() {
159	    if (this.props.chart.chartType === undefined) {
160	      if (this.props.chart.xAxis === 'series') {
161	        return barInfo;
162	      } else if (this.props.data.some(m => m.datapoints.some(dp => dp.y0))) {
163	        return areaInfo;
164	      } else {
165	        return lineInfo;
166	      }
167	    }
168	    const chartType = this.props.chart.chartType;
169	    switch (chartType) {
170	      case 'area':
171	        return areaInfo;
172	      case 'bar':
173	        return barInfo;
174	      case 'scatter':
175	        return scatterInfo;
176	      case 'line':
177	      default:
178	        return lineInfo;
179	    }
180	  }
181	
182	  private renderChart() {
183	    if (this.state.collapsed) {
184	      return undefined;
185	    }
186	    const typeData = this.determineChartType();
187	    const minDomain = this.props.chart.min === undefined ? undefined : { y: this.props.chart.min };
188	    const maxDomain = this.props.chart.max === undefined ? undefined : { y: this.props.chart.max };
189	    return (
190	      <ChartWithLegend
191	        chartHeight={this.getInnerChartHeight()}
192	        data={this.props.data}
193	        seriesComponent={typeData.seriesComponent}
194	        fill={typeData.fill}
195	        stroke={typeData.stroke}
196	        showSpans={this.props.showSpans}
197	        showTrendline={this.props.showTrendline}
198	        groupOffset={typeData.groupOffset}
199	        sizeRatio={typeData.sizeRatio}
200	        overlay={this.props.overlay}
201	        unit={this.props.chart.unit}
202	        isMaximized={this.props.isMaximized}
203	        moreChartProps={{ minDomain: minDomain, maxDomain: maxDomain }}
204	        onClick={this.props.onClick}
205	        brushHandlers={this.props.brushHandlers}
206	        timeWindow={this.props.timeWindow}
207	        xAxis={this.props.chart.xAxis}
208	      />
209	    );
210	  }
211	
212	  private isEmpty(): boolean {
213	    return !this.props.data.some(s => s.datapoints.length !== 0);
214	  }
215	
216	  private renderEmpty() {
217	    const chartHeight = this.getInnerChartHeight();
218	    return chartHeight > MIN_HEIGHT ? (
219	      <div
220	        style={{
221	          display: 'flex',
222	          justifyContent: 'center',
223	          alignItems: 'center',
224	          overflow: 'hidden',
225	          height: chartHeight > MIN_HEIGHT_YAXIS ? chartHeight - LEGEND_HEIGHT : chartHeight,
226	          textAlign: 'center',
227	          borderLeft: `2px solid ${PFColors.ColorLight200}`,
228	          borderBottom: `2px solid ${PFColors.ColorLight200}`
229	        }}
230	      >
231	        <EmptyState variant={EmptyStateVariant.sm} className={emptyStyle}>
232	          {this.props.isMaximized && <EmptyStateIcon icon={CubesIcon} />}
233	          <EmptyStateBody className={emptyStyle}>No data available</EmptyStateBody>
234	        </EmptyState>
235	      </div>
236	    ) : undefined;
237	  }
238	
239	  private renderError() {
240	    return (
241	      <div
242	        style={{
243	          display: 'flex',
244	          justifyContent: 'center',
245	          alignItems: 'center',
246	          overflow: 'hidden',
247	          height: this.getInnerChartHeight(),
248	          textAlign: 'center'
249	        }}
250	      >
251	        <EmptyState variant={EmptyStateVariant.sm} className={emptyStyle}>
252	          {this.props.isMaximized && (
253	            <EmptyStateIcon
254	              icon={() => <ErrorCircleOIcon style={{ color: PFColors.Danger }} width={32} height={32} />}
255	            />
256	          )}
257	          <EmptyStateBody className={emptyStyle}>
258	            An error occured while fetching this metric:
259	            <p>
260	              <i>{this.props.chart.error}</i>
261	            </p>
262	          </EmptyStateBody>
263	        </EmptyState>
264	      </div>
265	    );
266	  }
267	}

