182	    if (this.state.collapsed) {
183	      return undefined;
184	    }
185	    const typeData = this.determineChartType();
186	    const minDomain = this.props.chart.min === undefined ? undefined : { y: this.props.chart.min };
187	    const maxDomain = this.props.chart.max === undefined ? undefined : { y: this.props.chart.max };
188	    return (
189	      <ChartWithLegend
190	        chartHeight={this.getInnerChartHeight()}
191	        data={this.props.data}
192	        seriesComponent={typeData.seriesComponent}
193	        fill={typeData.fill}
194	        stroke={typeData.stroke}
195	        showSpans={this.props.showSpans}
196	        showTrendline={this.props.showTrendline}
197	        groupOffset={typeData.groupOffset}
198	        sizeRatio={typeData.sizeRatio}
199	        overlay={this.props.overlay}
200	        unit={this.props.chart.unit}
201	        isMaximized={this.props.isMaximized}
202	        moreChartProps={{ minDomain: minDomain, maxDomain: maxDomain }}
203	        onClick={this.props.onClick}
204	        brushHandlers={this.props.brushHandlers}
205	        timeWindow={this.props.timeWindow}
206	        xAxis={this.props.chart.xAxis}
207	      />
208	    );
209	  }
210	
211	  private isEmpty(): boolean {
212	    return !this.props.data.some(s => s.datapoints.length !== 0);
213	  }
214	
215	  private renderEmpty() {
216	    const chartHeight = this.getInnerChartHeight();
217	    return chartHeight > MIN_HEIGHT ? (
218	      <div
219	        style={{
220	          display: 'flex',
221	          justifyContent: 'center',
222	          alignItems: 'center',
223	          overflow: 'hidden',
224	          height: chartHeight > MIN_HEIGHT_YAXIS ? chartHeight - LEGEND_HEIGHT : chartHeight,
225	          textAlign: 'center',
226	          borderLeft: `2px solid ${PFColors.ColorLight200}`,
227	          borderBottom: `2px solid ${PFColors.ColorLight200}`
228	        }}
229	      >
230	        <EmptyState variant={EmptyStateVariant.sm} className={emptyStyle} icon={this.props.isMaximized ? CubesIcon : undefined}>
231	          <EmptyStateBody className={emptyStyle}>No data available</EmptyStateBody>
232	        </EmptyState>
233	      </div>
234	    ) : undefined;
235	  }
236	
237	  private renderError() {
238	    return (
239	      <div
240	        style={{
241	          display: 'flex',
242	          justifyContent: 'center',
243	          alignItems: 'center',
244	          overflow: 'hidden',
245	          height: this.getInnerChartHeight(),
246	          textAlign: 'center'
247	        }}
248	      >
249	        <EmptyState variant={EmptyStateVariant.sm} className={emptyStyle} icon={this.props.isMaximized ? () => <ErrorCircleOIcon style={{ color: PFColors.Danger }} width={32} height={32} /> : undefined}>
250	          <EmptyStateBody className={emptyStyle}>
251	            An error occured while fetching this metric:
252	            <p>
253	              <i>{this.props.chart.error}</i>
254	            </p>
255	          </EmptyStateBody>
256	        </EmptyState>
257	      </div>
258	    );
259	  }
260	}
